pub async fn edges(
        &self,
        entry_id: &str,
        relation: Option<&str>,
    ) -> Result<Vec<EdgeDto>> {
        let mut url = format!("{}/v1/entries/{}/edges", self.base_url, entry_id);
        if let Some(rel) = relation {
            url = format!("{}?relation={}", url, rel);
        }

        let resp = self
            .client
            .get(&url)
            .send()
            .await?
            .error_for_status()?;

        Ok(resp.json().await?)
    }
